import org.junit.jupiter.api.Test;

class LmdbNativeRowStepIterationTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final long P1 = 100;
	private static final long P2 = 200;

	@Test
	void evaluateDoesNotConsumeRowsBeforeIterationDemand() {
		RecordingPlan plan = new RecordingPlan(2);
		NativeRowsStep step = new NativeRowsStep(null, plan, NativeSlotLayout.empty(), new int[0], new String[0],
				false, new int[0], new boolean[0], 0, -1, true, null, null, null, Set.of(), null, null);

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertThat(plan.openCalls).as("cursor opens during evaluate()").isZero();
			assertThat(plan.nextCalls).as("rows consumed during evaluate()").isZero();

			assertThat(iteration.hasNext()).isTrue();
			assertThat(plan.openCalls).as("cursor opens on first demand").isOne();
			assertThat(plan.nextCalls).as("only one row is consumed for first demand").isOne();
		}

		assertThat(plan.closeCalls).as("active cursor closes with the result iteration").isOne();
	}

	@Test
	void closeIsIdempotentAndDropsRetainedDistinctState() {
		RecordingPlan plan = new RecordingPlan(2);
		NativeRowsStep step = new NativeRowsStep(null, plan, NativeSlotLayout.empty(), new int[0], new String[0],
				true, new int[0], new boolean[0], 0, -1, true, null, null, null, Set.of(), null, null);
		NativeRowsIteration iteration = (NativeRowsIteration) step.evaluate(EmptyBindingSet.getInstance());

		assertThat(iteration.hasNext()).isTrue();
		assertThat(iteration.distinctRows.emptySeen).isTrue();

		iteration.close();
		iteration.close();

		assertThat(iteration.hasNext()).isFalse();
		assertThat(iteration.distinctRows).as("DISTINCT tuple state is released on close").isNull();
		assertThat(iteration.cursor).as("active cursor is released on close").isNull();
		assertThat(iteration.base).as("incoming bindings are released on close").isNull();
		assertThat(iteration.step).as("compiled step is released on close").isNull();
		assertThat(plan.nextCalls).as("close does not enumerate remaining rows").isOne();
		assertThat(plan.closeCalls).as("cursor close is idempotent").isOne();
	}

	@Test
	void factorizedFirstResultDoesNotProjectRemainingCartesianProduct() {
		RecordingNativeSource source = new RecordingNativeSource();
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("s1", 0, "o1", 1, "s2", 2, "o2", 3), null);
		layout.freeze(List.of("s1", "o1", "s2", "o2"));
		PatternPlan left = pattern(0, P1, 1);
		PatternPlan right = pattern(2, P2, 3);
		MultiJoinPlan join = new MultiJoinPlan(new SlotPlan[] { left, right }, new MaskedFilter[0]);
		NativeRowsStep step = new NativeRowsStep(source, join, layout, new int[] { 0, 1, 2, 3 },
				new String[] { "s1", "o1", "s2", "o2" }, false, new int[0], new boolean[0], 0, -1, true,
				null, null, null, Set.of(), null, null);
		long engagements = LmdbNativeFactorizedRows.ENGAGED.get();

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertThat(source.statementCalls).as("factorized scans before iteration demand").isZero();
			assertThat(iteration.hasNext()).isTrue();
			assertThat(LmdbNativeFactorizedRows.ENGAGED.get()).isEqualTo(engagements + 1);
			assertThat(source.statementCalls).as("each independent tail branch scans once").isEqualTo(2);
			assertThat(source.lazyValueCalls).as("projection keeps the first row as native ids").isZero();
			assertThat(iteration.next()).hasSize(4);
			assertThat(source.lazyValueCalls).as("inspecting that row materializes only its four values").isEqualTo(4);
		}

		assertThat(source.closedIterators).as("retained tail probes close on early result close").isEqualTo(2);
	}

	private static PatternPlan pattern(int subjectSlot, long predicate, int objectSlot) {
		return new PatternPlan(Term.slot(subjectSlot), Term.constant(predicate), Term.slot(objectSlot), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 3);
	}

	private static final class RecordingPlan implements SlotPlan {
		private final int rows;
		private int openCalls;
		private int nextCalls;
		private int closeCalls;

		private RecordingPlan(int rows) {
			this.rows = rows;
		}

		@Override
		public RowCursor open(RowState row) {
			openCalls++;
			return new RowCursor() {
				private int emitted;

				@Override
				public boolean next() {
					nextCalls++;
					return emitted++ < rows;
				}

				@Override
				public void close() {
					closeCalls++;
				}
			};
		}

		@Override
		public long producedMask() {
			return 0;
		}
	}

	private static final class RecordingNativeSource implements NativeLmdbQuerySource {
		private int statementCalls;
		private int lazyValueCalls;
		private int closedIterators;

		@Override
		public long idOf(Value value) {
			return UNKNOWN_ID;
		}

		@Override
		public Value lazyValue(long id) {
			lazyValueCalls++;
			return VF.createIRI("urn:test:id:" + id);
		}

		@Override
		public Object idSpace() {
			return this;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			statementCalls++;
			long base = pred == P1 ? 10 : 30;
			return new RecordIterator() {
				private int index;
				private boolean closed;

				@Override
				public long[] next() {
					if (closed || index == 3) {
						return null;
					}
					long id = base + index++;
					return new long[] { id, pred, id + 10, 0 };
				}

				@Override
				public void close() {
					if (!closed) {
						closed = true;
						closedIterators++;
					}
				}
			};
		}

		@Override
		public long count(long subj, long pred, long obj, long context) {
			return 3;
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) {
			return true;
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return 3;
		}

		@Override
		public boolean hasStatementsInSource() {
			return true;
		}
	}
}
